use regex::Regex;
use std::collections::HashMap;

fn solve(code: Vec<String>, businessLine: Vec<String>, isActive: Vec<bool>) -> Vec<String> {
    let regex = Regex::new(r"^[a-zA-Z0-9_]+$").unwrap();
    let business_order: HashMap<&str, usize> = [
        ("electronics", 0),
        ("grocery", 1),
        ("pharmacy", 2),
        ("restaurant", 3),
    ].into_iter().collect();

    let mut valid = Vec::new();
    for i in 0..code.len() {
        let c = &code[i];
        let bl = &businessLine[i];
        let active = isActive[i];

        if !c.is_empty() && regex.is_match(c) && (bl == "electronics" || bl == "grocery" || bl == "pharmacy" || bl == "restaurant") && active {
            valid.push((c.clone(), bl.to_string()));
        }
    }

    valid.sort_by(|a, b| {
        let a_order = business_order[&a.1];
        let b_order = business_order[&b.1];
        a_order.cmp(&b_order)
    });

    valid.into_iter().map(|x| x.0).collect()
}
